// Used inside a ModelContainer + ModelContext (see SwiftData/Core Data answers).

import CoreData

// Container — usually a singleton (or injected service)
final class CoreDataStack {
  static let shared = CoreDataStack()
  let container: NSPersistentContainer
  private init() {
    container = NSPersistentContainer(name: "MyApp")
    container.loadPersistentStores { _, error in
      if let error { fatalError("Core Data load failed: \(error)") }
    }
  }
  var viewContext: NSManagedObjectContext { container.viewContext }
  func newBackgroundContext() -> NSManagedObjectContext { container.newBackgroundContext() }
}

// Insert
let ctx = CoreDataStack.shared.viewContext
let user = User(context: ctx)
user.id = UUID()
user.name = "Alice"
try ctx.save()

// Fetch with predicate + sort
let fr: NSFetchRequest<User> = User.fetchRequest()
fr.predicate = NSPredicate(format: "name BEGINSWITH %@", "A")
fr.sortDescriptors = [NSSortDescriptor(keyPath: \User.name, ascending: true)]
fr.fetchLimit = 50
let results = try ctx.fetch(fr)

// Background work — must run on the context's queue
let bg = CoreDataStack.shared.newBackgroundContext()
bg.perform {
  // bulk import — much faster than per-row save
  for dto in dtos {
    let u = User(context: bg)
    u.id = dto.id; u.name = dto.name
  }
  try? bg.save()
}

// Batch update — bypasses object graph for huge changes
let batch = NSBatchUpdateRequest(entityName: "User")
batch.predicate = NSPredicate(format: "isStale == YES")
batch.propertiesToUpdate = ["isStale": false]
batch.resultType = .updatedObjectsCountResultType
_ = try ctx.execute(batch)

import SwiftUI
import SwiftData

@Model
final class TodoItem {
  @Attribute(.unique) var id: UUID = UUID()
  var title: String
  var done: Bool
  var createdAt: Date = Date()
  init(title: String, done: Bool = false) { self.title = title; self.done = done }
}

// SwiftUI integration
@main
struct MyApp: App {
  var body: some Scene {
    WindowGroup { TodoListView() }
      .modelContainer(for: TodoItem.self)
  }
}

struct TodoListView: View {
  @Environment(\.modelContext) private var ctx
  @Query(sort: \TodoItem.createdAt, order: .reverse) private var items: [TodoItem]

  var body: some View {
    List {
      ForEach(items) { item in
        Toggle(isOn: Binding(get: { item.done }, set: { item.done = $0 })) {
          Text(item.title)
        }
      }
      .onDelete { indexes in
        for i in indexes { ctx.delete(items[i]) }
      }
    }
    .toolbar {
      Button("Add") {
        ctx.insert(TodoItem(title: "New"))
      }
    }
  }
}

