import Security
import Foundation

enum Keychain {
  static func save(_ value: Data, account: String) throws {
    let query: [String: Any] = [
      kSecClass as String: kSecClassGenericPassword,
      kSecAttrAccount as String: account,
      kSecValueData as String: value,
      kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly,
    ]
    SecItemDelete(query as CFDictionary) // remove existing if any
    let status = SecItemAdd(query as CFDictionary, nil)
    guard status == errSecSuccess else { throw KeychainError(status: status) }
  }

  static func read(account: String) -> Data? {
    let query: [String: Any] = [
      kSecClass as String: kSecClassGenericPassword,
      kSecAttrAccount as String: account,
      kSecReturnData as String: true,
      kSecMatchLimit as String: kSecMatchLimitOne,
    ]
    var item: CFTypeRef?
    let status = SecItemCopyMatching(query as CFDictionary, &item)
    return status == errSecSuccess ? item as? Data : nil
  }

  static func delete(account: String) {
    let query: [String: Any] = [
      kSecClass as String: kSecClassGenericPassword,
      kSecAttrAccount as String: account,
    ]
    SecItemDelete(query as CFDictionary)
  }
  struct KeychainError: Error { let status: OSStatus }
}

// Usage
try Keychain.save(Data("jwt".utf8), account: "access_token")
let token = Keychain.read(account: "access_token").flatMap { String(data: $0, encoding: .utf8) }

// Biometric-protected item
import LocalAuthentication
let ctx = LAContext()
let access = SecAccessControlCreateWithFlags(nil, kSecAttrAccessibleWhenUnlockedThisDeviceOnly, .biometryCurrentSet, nil)!
let bioQuery: [String: Any] = [
  kSecClass as String: kSecClassGenericPassword,
  kSecAttrAccount as String: "bio_secret",
  kSecValueData as String: Data("secret".utf8),
  kSecAttrAccessControl as String: access,
]
SecItemAdd(bioQuery as CFDictionary, nil)

// Lightweight Core Data migration — set options on the store description
let desc = container.persistentStoreDescriptions.first!
desc.shouldMigrateStoreAutomatically = true
desc.shouldInferMappingModelAutomatically = true

// Custom migration policy
final class UserToProfilePolicy: NSEntityMigrationPolicy {
  override func createDestinationInstances(forSource src: NSManagedObject,
                                           in mapping: NSEntityMapping,
                                           manager: NSMigrationManager) throws {
    let dest = NSEntityDescription.insertNewObject(
      forEntityName: mapping.destinationEntityName!,
      into: manager.destinationContext
    )
    dest.setValue(src.value(forKey: "name"), forKey: "displayName")
    dest.setValue((src.value(forKey: "email") as? String)?.lowercased(), forKey: "email")
    manager.associate(sourceInstance: src, withDestinationInstance: dest, for: mapping)
  }
}

// SwiftData versioned schema
import SwiftData
enum SchemaV1: VersionedSchema {
  static var versionIdentifier = Schema.Version(1, 0, 0)
  static var models: [any PersistentModel.Type] { [TodoItem.self] }
}
enum SchemaV2: VersionedSchema {
  static var versionIdentifier = Schema.Version(2, 0, 0)
  static var models: [any PersistentModel.Type] { [TodoItemV2.self] }
}

enum AppMigrationPlan: SchemaMigrationPlan {
  static var schemas: [any VersionedSchema.Type] { [SchemaV1.self, SchemaV2.self] }
  static var stages: [MigrationStage] { [.lightweight(fromVersion: SchemaV1.self, toVersion: SchemaV2.self)] }
}

let container = try ModelContainer(for: TodoItemV2.self, migrationPlan: AppMigrationPlan.self)

